#!/usr/bin/env bash
set -euo pipefail

ROOT="$(cd "$(dirname "$0")/../../../.." && pwd)"
cd "$ROOT"

MODEL_ID="flux-1-schnell"
SOURCE_HF="black-forest-labs/FLUX.1-schnell"
MODEL_SCRATCH="${MODEL_SCRATCH:-$ROOT/.a0/model-scratch/flux-1-schnell}"
OUT_DIR="$MODEL_SCRATCH/out"
KNOT_PATH="$OUT_DIR/flux-1-schnell.knot"
MANIFEST_PATH="$OUT_DIR/flux-1-schnell.knot.manifest.json"
ADMISSION_PATH="$OUT_DIR/flux-1-schnell.knot.admission.json"
PREFLIGHT_REPORT=".a0/runs/unsound-diffusion/real/flux-1-schnell.local-preflight.json"
ARTIFACT_REPORT=".a0/runs/unsound-diffusion/real/flux-1-schnell.artifact-locator.json"
REMOTE_BASE="https://edgework-web.taylorbuley.workers.dev/api/v1/r2/distributed-inference/models"
PROXY_BASE_DEFAULT="https://edgework-web.taylorbuley.workers.dev/api/v1/r2/distributed-inference"
XRANGER_R2_PROXY_BASE_DEFAULT="https://edgework-web.taylorbuley.workers.dev/api/v1/r2"
WRANGLER_ENV_FILE="${WRANGLER_ENV_FILE:-.env.local}"
R2_BUCKET="${R2_BUCKET:-distributed-inference}"
PROMPT="a surreal Dali landscape, melting brass clocks over a luminous desert coastline, impossible long shadows, dreamlike watercolor detail"

env_file_value() {
  local key="$1"
  if [[ ! -f "$WRANGLER_ENV_FILE" ]]; then
    return 1
  fi
  awk -v key="$key" '
    index($0, key "=") == 1 {
      sub("^[^=]*=", "")
      gsub(/^"/, "")
      gsub(/"$/, "")
      gsub(/^'\''/, "")
      gsub(/'\''$/, "")
      print
      exit
    }
  ' "$WRANGLER_ENV_FILE"
}

load_env_tokens() {
  if [[ -z "${HF_TOKEN:-}" && -z "${HUGGINGFACE_TOKEN:-}" ]]; then
    local hf_from_file
    hf_from_file="$(env_file_value HUGGINGFACE_TOKEN || true)"
    if [[ -n "$hf_from_file" ]]; then
      export HF_TOKEN="$hf_from_file"
    fi
  fi
  if [[ -z "${R2_TOKEN:-}" ]]; then
    local r2_from_file
    r2_from_file="$(env_file_value R2_TOKEN || true)"
    if [[ -n "$r2_from_file" ]]; then
      export R2_TOKEN="$r2_from_file"
    fi
  fi
  if [[ -z "${CLOUDFLARE_API_TOKEN:-}" ]]; then
    local cf_from_file
    cf_from_file="$(env_file_value CLOUDFLARE_API_TOKEN || true)"
    if [[ -n "$cf_from_file" ]]; then
      export CLOUDFLARE_API_TOKEN="$cf_from_file"
    fi
  fi
  if [[ -z "${CLOUDFLARE_ACCOUNT_ID:-}" ]]; then
    local cf_account_from_file
    cf_account_from_file="$(env_file_value CLOUDFLARE_ACCOUNT_ID || true)"
    if [[ -n "$cf_account_from_file" ]]; then
      export CLOUDFLARE_ACCOUNT_ID="$cf_account_from_file"
    fi
  fi
}

preflight() {
  load_env_tokens
  node open-source/gnosis/distributed-inference/scripts/check-flux-schnell-build-env.mjs \
    --scratch "$MODEL_SCRATCH" \
    --output "$PREFLIGHT_REPORT" \
    "$@"
}

ensure_python_env() {
  mkdir -p "$MODEL_SCRATCH/hf" "$MODEL_SCRATCH/tmp" "$OUT_DIR"
  if [[ ! -x "$MODEL_SCRATCH/venv/bin/python3" ]]; then
    python3 -m venv "$MODEL_SCRATCH/venv"
  fi
  "$MODEL_SCRATCH/venv/bin/pip" install --upgrade pip
  "$MODEL_SCRATCH/venv/bin/pip" install \
    --no-cache-dir \
    transformers \
    safetensors \
    numpy \
    requests \
    "huggingface_hub>=0.24" \
    hf_transfer \
    ml_dtypes
}

encode_knot() {
  load_env_tokens
  preflight
  ensure_python_env
  export HF_HOME="$MODEL_SCRATCH/hf"
  export TMPDIR="$MODEL_SCRATCH/tmp"
  export HF_HUB_ENABLE_HF_TRANSFER="${HF_HUB_ENABLE_HF_TRANSFER:-0}"
  export HF_HUB_DISABLE_XET="${HF_HUB_DISABLE_XET:-1}"
  export HF_XET_HIGH_PERFORMANCE="${HF_XET_HIGH_PERFORMANCE:-0}"
  export KNOT_FORCE_F32=0
  export KNOT_STREAM_DIRECT=1
  export KNOT_DELETE_SHARDS_AFTER_ENCODE=1
  export KNOT_HEADER_RESERVE_BYTES="${KNOT_HEADER_RESERVE_BYTES:-2097152}"
  if [[ -n "${HF_TOKEN:-${HUGGINGFACE_TOKEN:-}}" ]]; then
    export HF_TOKEN="${HF_TOKEN:-$HUGGINGFACE_TOKEN}"
  fi

  args=(
    open-source/gnosis/distributed-inference/encode-knot.py
    --model "$SOURCE_HF"
    --output "$KNOT_PATH"
  )

  "$MODEL_SCRATCH/venv/bin/python3" "${args[@]}"
}

write_sidecars() {
  python3 open-source/gnosis/distributed-inference/scripts/write-flux-knot-sidecars.py \
    --knot "$KNOT_PATH" \
    --model-id "$MODEL_ID" \
    --source-hf "$SOURCE_HF" \
    --artifact models/flux-1-schnell.knot
}

assert_local() {
  test -s "$KNOT_PATH"
  write_sidecars
  test -s "$MANIFEST_PATH"
  test -s "$ADMISSION_PATH"
}

probe_knot() {
  assert_local
  pnpm run a0 -- run distributed-inference:build-flux-probe --skip-nx-cache
  open-source/gnosis/distributed-inference/target/release/flux-probe \
    --knot "$KNOT_PATH" \
    --prompt "$PROMPT" \
    --output "$OUT_DIR/flux-1-schnell.probe.png" \
    --manifest "$OUT_DIR/flux-1-schnell.probe.json" \
    --steps 6 \
    --guidance 3.5 \
    --seed 42 \
    --width 256 \
    --height 256
}

assert_remote() {
  node open-source/gnosis/distributed-inference/scripts/check-flux-knot-artifacts.mjs \
    --model-id "$MODEL_ID" \
    --base "$REMOTE_BASE" \
    --key flux-1-schnell.knot \
    --key flux-1-schnell.knot.manifest.json \
    --key flux-1-schnell.knot.admission.json \
    --output "$ARTIFACT_REPORT" \
    --fail-on-missing
}

upload_artifacts() {
  load_env_tokens
  assert_local
  if [[ -n "${R2_TOKEN:-}" ]]; then
    preflight --require-r2 --min-free-gib 1
    ensure_python_env
    export PROXY_BASE="${PROXY_BASE:-$PROXY_BASE_DEFAULT}"
    "$MODEL_SCRATCH/venv/bin/python3" open-source/gnosis/distributed-inference/upload-to-r2.py \
      "$KNOT_PATH" \
      models/flux-1-schnell.knot
    "$MODEL_SCRATCH/venv/bin/python3" open-source/gnosis/distributed-inference/upload-to-r2.py \
      "$MANIFEST_PATH" \
      models/flux-1-schnell.knot.manifest.json
    "$MODEL_SCRATCH/venv/bin/python3" open-source/gnosis/distributed-inference/upload-to-r2.py \
      "$ADMISSION_PATH" \
      models/flux-1-schnell.knot.admission.json
  else
    if [[ -z "${CLOUDFLARE_API_TOKEN:-}" ]]; then
      echo "ERROR: R2_TOKEN is absent and CLOUDFLARE_API_TOKEN is unavailable for x-ranger multipart upload." >&2
      exit 1
    fi
    XRANGER_R2_PROXY_BASE="${XRANGER_R2_PROXY_BASE:-$XRANGER_R2_PROXY_BASE_DEFAULT}" pnpm run a0 -- xr r2 put \
      "$R2_BUCKET/models/flux-1-schnell.knot" \
      --file "$KNOT_PATH" \
      --content-type application/octet-stream
    XRANGER_R2_PROXY_BASE="${XRANGER_R2_PROXY_BASE:-$XRANGER_R2_PROXY_BASE_DEFAULT}" pnpm run a0 -- xr r2 put \
      "$R2_BUCKET/models/flux-1-schnell.knot.manifest.json" \
      --file "$MANIFEST_PATH" \
      --content-type application/json
    XRANGER_R2_PROXY_BASE="${XRANGER_R2_PROXY_BASE:-$XRANGER_R2_PROXY_BASE_DEFAULT}" pnpm run a0 -- xr r2 put \
      "$R2_BUCKET/models/flux-1-schnell.knot.admission.json" \
      --file "$ADMISSION_PATH" \
      --content-type application/json
  fi
  assert_remote
}

build_local() {
  encode_knot
  assert_local
  probe_knot
}

admit_production() {
  assert_remote
  pnpm run a0 -- run @a0n/inference-runtime:admit-unsound-flux-schnell-production --skip-nx-cache
}

case "${1:-build}" in
  preflight)
    shift
    preflight "$@"
    ;;
  encode)
    encode_knot
    ;;
  sidecars)
    write_sidecars
    ;;
  assert-local)
    assert_local
    ;;
  probe)
    probe_knot
    ;;
  build)
    build_local
    ;;
  upload)
    upload_artifacts
    ;;
  assert-remote)
    assert_remote
    ;;
  admit)
    admit_production
    ;;
  all)
    build_local
    upload_artifacts
    admit_production
    ;;
  *)
    echo "usage: $0 {preflight|encode|sidecars|assert-local|probe|build|upload|assert-remote|admit|all}" >&2
    exit 2
    ;;
esac
